function callAgent(prompt) {
  console.log('  рџ¤– Calling gpu-dev...');
  
  try {
    // Create temp file with prompt
    const tempFile = `/tmp/agent-prompt-${Date.now()}.txt`;
    fs.writeFileSync(tempFile, prompt);
    
    // Call kiro-cli (this would work if kiro-cli is available)
    // For now, return placeholder
    
    // In production:
    // const result = execSync(`cat ${tempFile} | kiro-cli chat --agent gpu-dev --output-only`, {
    //   encoding: 'utf8',
    //   timeout: 30000
    // });
    
    // Clean up
    fs.unlinkSync(tempFile);
    
    // For demo, return minimal implementation
    return generateMinimalImplementation(prompt);
    
  } catch (error) {
    console.error('  вќЊ Agent call failed:', error.message);
    return generateMinimalImplementation(prompt);
  }
}

function generateMinimalImplementation(prompt) {
  // Extract class name from prompt
  const match = prompt.match(/class (\w+)/);
  const className = match ? match[1] : 'Component';
  
  return `// ${className}
// Auto-generated by bootstrap

${prompt.split('\n\n')[1] || '// Implementation'}

module.exports = ${className};
`;
}

function extractCode(output) {
  // Extract code block from agent output
  const match = output.match(/\`\`\`(?:javascript|js)?\n([\s\S]*?)\n\`\`\`/);
  return match ? match[1] : output;
}

async function buildComponent(comp) {
  console.log(`\nрџ“¦ Building ${comp.name}...`);
  
  const startTime = Date.now();
  
  // Call agent to generate code
  const output = callAgent(comp.prompt);
  const code = extractCode(output);
  
  // Ensure directory exists
  const dir = path.dirname(comp.file);
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
  }
  
  // Write file
  fs.writeFileSync(comp.file, code);
  
  const duration = (Date.now() - startTime) / 1000;
  const lines = code.split('\n').length;
  
  console.log(`  вњ… Generated ${lines} lines in ${duration.toFixed(1)}s`);
  console.log(`  рџ“Ѓ ${comp.file}`);
  
  return { name: comp.name, file: comp.file, lines, duration };
}

